library(dslabs)

data(“polls_us_election_2016”)

my_first &lt;- “Emre”
my_birth_year &lt;- 2001

k &lt;- (nchar(my_first) + my_birth_year) %% 15 + 8

if (k %% 2 == 0) {
head(polls_us_election_2016, k)
} else {
tail(polls_us_election_2016, k)
}

total_na &lt;- sum(is.na(polls_us_election_2016))
total_na

na_per_column &lt;- sort(colSums(is.na(polls_us_election_2016)), decreasing = TRUE)
head(na_per_column, 8)

new_data &lt;- polls_us_election_2016

for (col in names(new_data)) {
if (is.numeric(new_data[[col]])) {
new_data[[col]][is.na(new_data[[col]])] &lt;- my_birth_year + k
} else {
new_data[[col]][is.na(new_data[[col]])] &lt;- paste0(my_first, “_”, k)
}
}

if (k %% 2 == 0) {
head(new_data, k)
} else {
tail(new_data, k)
}

sum(is.na(new_data))
anyNA(new_data)
